668→        ],
669→      );
670→      return;
671→    }
672→    const all = storageGet('settings-all', isSettingRowArray) ?? [];
673→    const existing = all.findIndex(r => r.key === key);
674→    if (existing >= 0) {
675→      all[existing] = {
