type DatabaseInstance = {
  execute(
    query: string,
    bindValues?: unknown[],
  ): Promise<{ rowsAffected: number }>;
  select<T>(query: string, bindValues?: unknown[]): Promise<T>;
};

let dbInstance: DatabaseInstance | undefined;
let dbPromise: Promise<DatabaseInstance> | undefined;

async function loadDb(): Promise<DatabaseInstance> {
  const Database = (await import('@tauri-apps/plugin-sql')).default;
  return Database.load(DB_PATH);
}

function getDb(): Promise<DatabaseInstance> {
  if (dbInstance) return Promise.resolve(dbInstance);
  if (dbPromise) return dbPromise;

  dbPromise = loadDb()
    .then(db => {
      dbInstance = db;
      return db;
    })
    .catch(err => {
      dbPromise = undefined;
      throw err;
    });

  return dbPromise;
}

const CLIPBOARD_COLUMNS = new Set<string>([
  'content',
  'content_type',
  'source_app',
  'copied_at',
  'pinned',
]);

const SNIPPET_COLUMNS = new Set<string>([
  'name',
  'keyword',
  'content',
  'category',
  'tags',
  'created_at',
]);

const QUICKLINK_COLUMNS = new Set<string>([
  'name',
  'link',
  'type',
  'application',
  'tags',
  'created_at',
]);

const NOTE_COLUMNS = new Set<string>([
  'title',
  'content',
  'created_at',
]);

function buildUpdateQuery(
  table: string,
  updates: Record<string, unknown>,
  allowedColumns: Set<string>,
  id: string
): {
  sql: string;
  values: unknown[];
} | null {
  const fields: string[] = [];
  const values: unknown[] = [];
  let idx = 1;

  for (const [key, value] of Object.entries(updates)) {
    if (!allowedColumns.has(key)) continue;
    fields.push(`${key} = $${idx}`);
    values.push(value);
    idx++;
  }

  if (fields.length === 0) return null;
  values.push(id);
  return {
    sql: `UPDATE ${table} SET ${fields.join(', ')} WHERE id = $${idx}`,
    values,
  };
}

function escapeFts5Query(query: string): string {
  return query
    .split(/\s+/)
    .filter(Boolean)
    .map(token => `"${token.replace(/"/g, '""')}"`)
    .join(' ');
}

function isClipboardRowArray(v: unknown): v is ClipboardEntryRow[] {
  if (!Array.isArray(v)) return false;
  return v.every(
    r =>
      typeof r === 'object' &&
      r !== null &&
      'id' in r &&
      typeof r.id === 'string' &&
      'content' in r &&
      typeof r.content === 'string' &&
      'copied_at' in r &&
      typeof r.copied_at === 'string',
  );
}

